package com.restaurantcraft.network; import com.restaurantcraft.entity.CustomerEntity; import net.minecraft.network.FriendlyByteBuf; import net.minecraft.server.level.ServerPlayer; import net.minecraftforge.network.NetworkEvent; import java.util.function.Supplier; public record C2SSubmitDishPacket(int entityId){ public static void encode(C2SSubmitDishPacket p,FriendlyByteBuf b){b.writeInt(p.entityId);} public static C2SSubmitDishPacket decode(FriendlyByteBuf b){return new C2SSubmitDishPacket(b.readInt());} public static void handle(C2SSubmitDishPacket p,Supplier<NetworkEvent.Context> c){c.get().enqueueWork(()->{ServerPlayer sp=c.get().getSender(); if(sp!=null&&sp.level().getEntity(p.entityId) instanceof CustomerEntity ce)ce.submitDish(sp);}); c.get().setPacketHandled(true);} }
